import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const menuLink =
  'text-lg font-semibold tracking-wide hover:text-[#E2ECFF] transition underline-offset-4 decoration-transparent hover:decoration-[#E2ECFF]';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav className="bg-[#0F243C] text-white shadow-lg">
      <div className="max-w-6xl mx-auto flex items-center justify-between px-4 py-4 sm:px-6">
        <Link to={user ? '/bookings/create' : '/login'} className="flex items-center gap-3">
          <img src="/Logo.png" alt="Logo" className="h-12 w-12 object-contain" />
          <div className="leading-tight">
            <p className="text-lg font-semibold">Moving Service Scheduler</p>
            <p className="text-sm text-[#C2D4E9]">Plan . Move . Relax</p>
          </div>
        </Link>
        <div className="flex items-center gap-6">
          {user ? (
            <>
              <Link to="/bookings/create" className={menuLink}>
                Our Services
              </Link>
              <Link to="/bookings/create" className={`${menuLink} underline`}>
                Get Quotes
              </Link>
              <Link to="/profile" className={menuLink}>
                View Bookings
              </Link>
              <button
                onClick={handleLogout}
                className="text-lg font-semibold tracking-wide hover:text-[#E2ECFF] transition"
              >
                Logout
              </button>
              <Link to="/profile" className="text-lg font-semibold underline decoration-white">
                Hi, {user.name || 'there'}
              </Link>
            </>
          ) : (
            <>
              <Link to="/login" className={menuLink}>
                Login
              </Link>
              <Link to="/register" className={menuLink}>
                Register
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
